import{_ as e,o as d,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const v=JSON.parse('{"title":"Link Analytics (New)","description":"","frontmatter":{"title":"Link Analytics (New)","slug":"link-analytics-new"},"headers":[],"relativePath":"marketer-hub/link-analytics-new.md","filePath":"marketer-hub/link-analytics-new.md"}'),r={name:"marketer-hub/link-analytics-new.md"};function o(i,t,s,u,c,l){return d(),n("div",null,[...t[0]||(t[0]=[a('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The Link Analytics data source provides link-level reporting on Branch link performance. Use it to understand how your links are performing across channels, campaigns, and platforms.</p><p>To learn more about Analysis, read our <a href="./analysis-dashboards-overview.html">Dashboards Overview</a> article. To learn about all available data sources, read our <a href="./analysis-data-sources-new.html">Analysis Data Sources</a> article.</p><h2 id="when-to-use-this-data-source" tabindex="-1">When to use this data source <a class="header-anchor" href="#when-to-use-this-data-source" aria-label="Permalink to &quot;When to use this data source&quot;">​</a></h2><p>Use the Link Analytics data source when you want to analyze link-level performance data, including clicks, impressions, and downstream conversions attributed to specific Branch links. This data source includes link-specific dimensions like Link Id, Link Title, Domain, and Browser that are not available in the standard Activity data source.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>When <a href="./analysis-dashboards.html#create-and-configure-widget">creating a widget</a>, select <strong>Link Analytics</strong> to access these fields.</p></div><h2 id="fields-reference" tabindex="-1">Fields reference <a class="header-anchor" href="#fields-reference" aria-label="Permalink to &quot;Fields reference&quot;">​</a></h2><p>The following fields are available in the Link Analytics data source.</p><table tabindex="0"><thead><tr><th>Field</th><th>Field Type</th><th>Description</th></tr></thead><tbody><tr><td>Achieve Level</td><td>Measure</td><td>Total count of Achieve Level Branch Standard Events</td></tr><tr><td>Achieve Level Unique</td><td>Measure</td><td>Total unique count of Achieve Level events</td></tr><tr><td>Ad Partner 3p</td><td>Dimension</td><td>The attributed ad partner via their Branch code (3p)</td></tr><tr><td>Add Payment Info</td><td>Measure</td><td>Total count of Add Payment Info Branch Standard Events</td></tr><tr><td>Add Payment Info Unique</td><td>Measure</td><td>Unique count of Add Payment Info events</td></tr><tr><td>Add To Cart</td><td>Measure</td><td>Total count of Add to Cart Branch Standard Events</td></tr><tr><td>Add To Cart Unique</td><td>Measure</td><td>Unique count of Add to Cart events</td></tr><tr><td>Add To Wishlist</td><td>Measure</td><td>Total count of Add to Wishlist Branch Standard Events</td></tr><tr><td>Add To Wishlist Unique</td><td>Measure</td><td>Total unique count of Add to Wishlist events</td></tr><tr><td>App Id</td><td>Dimension</td><td>The Branch App Id</td></tr><tr><td>Attributed</td><td>Dimension</td><td>Indicates whether Branch was able to attribute the conversion event</td></tr><tr><td>Branch Channel</td><td>Dimension</td><td>Identifies which Branch product or feature measured the attributed event</td></tr><tr><td>Branch Cta View</td><td>Measure</td><td>Total count of CTA View Branch Standard Events</td></tr><tr><td>Branch Cta View Unique</td><td>Measure</td><td>Unique count of CTA View events</td></tr><tr><td>Branch Source</td><td>Dimension</td><td>The Branch source associated with the link</td></tr><tr><td>Browser</td><td>Dimension</td><td>The browser used during the link interaction</td></tr><tr><td>Campaign</td><td>Dimension</td><td>The attributed campaign name</td></tr><tr><td>Campaign Id</td><td>Dimension</td><td>The attributed campaign ID</td></tr><tr><td>Channel</td><td>Dimension</td><td>The attributed Channel</td></tr><tr><td>Click Ad</td><td>Measure</td><td>Total count of Click Ad Branch Standard Events</td></tr><tr><td>Click Ad Unique</td><td>Measure</td><td>Total unique count of Click Ad events</td></tr><tr><td>Clicks</td><td>Measure</td><td>Count of clicks on links</td></tr><tr><td>Clicks Unique</td><td>Measure</td><td>Unique count of clicks</td></tr><tr><td>Complete Registration</td><td>Measure</td><td>Total count of Complete Registration Branch Standard Events</td></tr><tr><td>Complete Registration Unique</td><td>Measure</td><td>Total unique count of Complete Registration events</td></tr><tr><td>Complete Stream</td><td>Measure</td><td>Total count of Complete Stream Branch Standard Events</td></tr><tr><td>Complete Stream Unique</td><td>Measure</td><td>Total unique count of Complete Stream events</td></tr><tr><td>Complete Tutorial</td><td>Measure</td><td>Total count of Complete Tutorial Branch Standard Events</td></tr><tr><td>Complete Tutorial Unique</td><td>Measure</td><td>Total unique count of Complete Tutorial events</td></tr><tr><td>Country</td><td>Dimension</td><td>The geographic country of the link interaction</td></tr><tr><td>Custom Event Template 0</td><td>Measure</td><td>Template to set up count of your Branch Custom Event KPI</td></tr><tr><td>Custom Event Unique Template 0</td><td>Measure</td><td>Template to set up unique count of your Branch Custom Event KPI</td></tr><tr><td>Date</td><td>Dimension</td><td>Time-series date</td></tr><tr><td>Domain</td><td>Dimension</td><td>The domain associated with the Branch link</td></tr><tr><td>Event Name</td><td>Dimension</td><td>The name of the Branch event</td></tr><tr><td>Feature</td><td>Dimension</td><td>Indicates what Branch feature or link campaign was attributed</td></tr><tr><td>Impression</td><td>Measure</td><td>Total count of impressions on Branch impression links</td></tr><tr><td>Impression Unique</td><td>Measure</td><td>Total unique count of impressions</td></tr><tr><td>Initiate Purchase</td><td>Measure</td><td>Total count of Initiate Purchase Branch Standard Events</td></tr><tr><td>Initiate Purchase Unique</td><td>Measure</td><td>Total unique count of Initiate Purchase events</td></tr><tr><td>Initiate Stream</td><td>Measure</td><td>Total count of Initiate Stream Branch Standard Events</td></tr><tr><td>Initiate Stream Unique</td><td>Measure</td><td>Total unique count of Initiate Stream events</td></tr><tr><td>Install</td><td>Measure</td><td>Total count of Install Branch Standard Events</td></tr><tr><td>Install Unique</td><td>Measure</td><td>Total unique count of Install events</td></tr><tr><td>Invite</td><td>Measure</td><td>Total count of Invite Branch Standard Events</td></tr><tr><td>Invite Unique</td><td>Measure</td><td>Total unique count of Invite events</td></tr><tr><td>Journeys Dismissal</td><td>Measure</td><td>Total count of Dismissed Branch Journey Banners</td></tr><tr><td>Journeys Dismissal Unique</td><td>Measure</td><td>Total unique count of Journeys Dismissal events</td></tr><tr><td>Link Id</td><td>Dimension</td><td>The unique identifier for the Branch link</td></tr><tr><td>Link Title</td><td>Dimension</td><td>The title assigned to the Branch link</td></tr><tr><td>Login</td><td>Measure</td><td>Total count of Login Branch Standard Events</td></tr><tr><td>Login Unique</td><td>Measure</td><td>Total unique count of Login events</td></tr><tr><td>Marketing Title</td><td>Dimension</td><td>Identifying title added to links</td></tr><tr><td>Open</td><td>Measure</td><td>Total count of Open Branch Standard Events</td></tr><tr><td>Open Unique</td><td>Measure</td><td>Total unique count of Open events</td></tr><tr><td>Opt In</td><td>Measure</td><td>Total count of Opt In Branch Standard Events</td></tr><tr><td>Opt In Unique</td><td>Measure</td><td>Total unique count of Opt In events</td></tr><tr><td>Opt Out</td><td>Measure</td><td>Total count of Opt Out Branch Standard Events</td></tr><tr><td>Opt Out Unique</td><td>Measure</td><td>Total unique count of Opt Out events</td></tr><tr><td>Os</td><td>Dimension</td><td>Indicates the Operating System of the device as retrieved via the Branch SDK</td></tr><tr><td>Pageview</td><td>Measure</td><td>Total count of Pageview Branch Standard Events</td></tr><tr><td>Pageview Unique</td><td>Measure</td><td>Total unique count of Pageview events</td></tr><tr><td>Platform</td><td>Dimension</td><td>Indicates the Platform of the device as retrieved via the Branch SDK</td></tr><tr><td>Purchase</td><td>Measure</td><td>Total count of Purchase Branch Standard Events</td></tr><tr><td>Purchase Unique</td><td>Measure</td><td>Total unique count of Purchase events</td></tr><tr><td>Rate</td><td>Measure</td><td>Total count of Rate Branch Standard Events</td></tr><tr><td>Rate Unique</td><td>Measure</td><td>Total unique count of Rate events</td></tr><tr><td>Reinstall</td><td>Measure</td><td>Total count of Reinstall Branch Standard Events</td></tr><tr><td>Reinstall Unique</td><td>Measure</td><td>Total unique count of Reinstall events</td></tr><tr><td>Reserve</td><td>Measure</td><td>Total count of Reserve Branch Standard Events</td></tr><tr><td>Reserve Unique</td><td>Measure</td><td>Total unique count of Reserve events</td></tr><tr><td>Search</td><td>Measure</td><td>Total count of Search Branch Standard Events</td></tr><tr><td>Search Unique</td><td>Measure</td><td>Total unique count of Search events</td></tr><tr><td>Share</td><td>Measure</td><td>Total count of Share Branch Standard Events</td></tr><tr><td>Share Unique</td><td>Measure</td><td>Total unique count of Share events</td></tr><tr><td>Spend Credits</td><td>Measure</td><td>Total count of Spend Credits Branch Standard Events</td></tr><tr><td>Spend Credits Unique</td><td>Measure</td><td>Total unique count of Spend Credits events</td></tr><tr><td>Start Trial</td><td>Measure</td><td>Total count of Start Trial Branch Standard Events</td></tr><tr><td>Start Trial Unique</td><td>Measure</td><td>Total unique count of Start Trial events</td></tr><tr><td>Subscribe</td><td>Measure</td><td>Total count of Subscribe Branch Standard Events</td></tr><tr><td>Subscribe Unique</td><td>Measure</td><td>Total unique count of Subscribe events</td></tr><tr><td>Tags</td><td>Dimension</td><td>User-generated tags on links</td></tr><tr><td>Uninstall</td><td>Measure</td><td>Total count of Uninstall Branch Standard Events</td></tr><tr><td>Uninstall Unique</td><td>Measure</td><td>Total unique count of Uninstall events</td></tr><tr><td>Unlock Achievement</td><td>Measure</td><td>Total count of Unlock Achievement Branch Standard Events</td></tr><tr><td>Unlock Achievement Unique</td><td>Measure</td><td>Total unique count of Unlock Achievement events</td></tr><tr><td>View Ad</td><td>Measure</td><td>Total count of View Ad Branch Standard Events</td></tr><tr><td>View Ad Unique</td><td>Measure</td><td>Total unique count of View Ad events</td></tr><tr><td>View Cart</td><td>Measure</td><td>Total count of View Cart Branch Standard Events</td></tr><tr><td>View Cart Unique</td><td>Measure</td><td>Total unique count of View Cart events</td></tr><tr><td>View Item</td><td>Measure</td><td>Total count of View Item Branch Standard Events</td></tr><tr><td>View Item Unique</td><td>Measure</td><td>Total unique count of View Item events</td></tr><tr><td>View Items</td><td>Measure</td><td>Total count of View Items Branch Standard Events</td></tr><tr><td>View Items Unique</td><td>Measure</td><td>Total unique count of View Items events</td></tr><tr><td>Web Session Start</td><td>Measure</td><td>Total count of Web Session Start Branch Standard Events</td></tr><tr><td>Web Session Start Unique</td><td>Measure</td><td>Total unique count of Web Session Start events</td></tr></tbody></table>',9)])])}const f=e(r,[["render",o]]);export{v as __pageData,f as default};
